import React, {useEffect, useState, useRef} from 'react'
import {useParams} from 'react-router-dom'
import {getSingleListing, getFilteredListing, createChatroom, sendMessage, getAllMessages, getChatroom} from '../WebAPI'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import heart from '../components/static/heart.png'
import Redheart from '../components/static/Redheart.png'
import ListingCard from '../components/ListingCard'
import {parseISO, differenceInMinutes} from 'date-fns'

const ListingWrapper = styled.div `
display:flex;
width:90%;
justify-content:center;
margin:20px auto;
`

const LeftInfoSection = styled.div `
width:25%;
display:flex;
justify-content:center;
align-items:flex-start;
height:100vh;
flex-direction:column;
font-size:1rem;
`

const ImageSection = styled.div `
width:50%;
overflow:scroll;
height:100vh;

::-webkit-scrollbar {
    display: none;
}
`

const Image = styled.div `
width:400px;
height:540px;
background-image:url(${props => props.image ? props.image : null});
background-size:contain;
background-position:center;
background-repeat:no-repeat;
margin:0 auto;
&+& {
	margin-top:30px;
}
`

const RightInfoSection = styled.div `
width:25%;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;

`

const ListingBrand = styled.div `
font-weight:500;
margin-bottom:20px;
font-size:1.2rem;
`

const ListingItemName = styled.div `
font-weight:900;
`

const ListingColor = styled.div `
font-size:0.8rem;
`

const ListingDescription = styled.div `
font-size:0.8rem;
width:90%;
white-space:pre-wrap;
margin-top:15px;
`

const ListingSize = styled.div `
font-size:0.9rem;
margin-top:30px;
`

const ListingCondition = styled.div `
font-size:1rem;
margin-bottom:20px;
`

const ListingPrice = styled.div `
font-size:0.9rem;

&:before {
	content:'$';
}
`

const Warning = styled.div `
font-size:0.5rem;
color:grey;
`

const AddToCart = styled.div `
width:160px;
height:45px;
line-height:45px;
text-align:center;
border-radius:5px;
border:1.5px solid #1C1C1C;
background-color:#1C1C1C;
color:white;
font-weight:900;
font-size:0.8rem;
margin:20px 0 10px 0;
transition:all 0.3s ease-in;
&:hover {
	cursor:pointer;
	background-color:white;
	color:#1C1C1C;
}
`

const Message = styled.div `
width:160px;
height:45px;
line-height:45px;
text-align:center;
border-radius:5px;
border:1.5px solid #1C1C1C;
background-color:white;
color:#1C1C1C;
font-weight:900;
font-size:0.8rem;
margin-bottom:20px;
transition:all 0.3s ease-in;
&:hover {
	cursor:pointer;
	background-color:#1C1C1C;
	color:white;
}
`

const Like = styled.div `
background-image:url(${heart});
background-position:center;
background-size:cover;
width:20px;
height:20px;
&:hover {
	cursor:pointer;
}
`

const Liked = styled.div `
background-image:url(${Redheart});
background-position:center;
background-size:cover;
width:20px;
height:20px;
&:hover {
	cursor:pointer;
}
`

const MoreFromThisDesigner = styled.div `
margin:0 auto;
width:90%;
`

const MoreFromThisDesignerTitle = styled.div `
font-size:1.2rem;
font-weight:900;
margin:30px 0;
`

const MessageBox = styled.div `
width:320px;
height:450px;
position:fixed;
top:40%;
left:75%;

`

const MessageBoxInput = styled.input `
height:10%;
background-color:white;
border:1px solid rgb(200, 200, 200);
border-radius:20px;
width:95%;
margin-top:112%;
padding:0 15px;
box-sizing:border-box;
&:focus {
	outline: none !important;
  }
`

const MessageBoxBody =styled.div `
height:90%;
background-color:white;
border:1.5px solid rgb(200, 200, 200);
border-radius:10px;
text-align:center;
`

export default function SingleListing () {
	const {id} = useParams()
	const [listingData, setListingData] = useState([{}])
	const [filteredListing, setFilteredListing] = useState([])
	const [isLiked, setIsLiked] = useState(false)
	const [chatroomActive, setChatroomActive] = useState(false)
	const [inputValue, setInputValue] = useState('')
	const [messageData, setMessageData] = useState([{}])
	const chatroomRef = useRef(null)

	const listingImage = Object.entries(listingData[0]).filter(data => data[0].indexOf('image') >= 0)
	const listingInfo = Object.fromEntries(Object.entries(listingData[0]).filter(data => data[0].indexOf('image') < 0))

	useEffect(() => {
		getSingleListing(id, setListingData)
		getFilteredListing(setFilteredListing, `designer=${listingInfo.designer_id}`)
	},[listingData[0].id])

	const onLike = () => {
		setIsLiked(!isLiked)
	}

	const onMessage = async () => {
		await getChatroom(listingData[0].id, listingData[0].user_id, chatroomRef)
		if (chatroomRef.current) {
			getAllMessages(chatroomRef.current.id, setMessageData)
		} else {
			createChatroom(localStorage.getItem('userId'), listingData[0].user_id, listingData[0].id)
		} 
		setChatroomActive(true)
	}

	const onInput = e => {
		setInputValue(e.target.value)
	}

	const onKeyin = e => {
		if (e.key === 'Enter') {
			sendMessage(inputValue, setMessageData, messageData, Number(localStorage.getItem('userId')), chatroomRef.current.id)
			setInputValue('')
		}
	}

	return (
		<>
			<Header />
			<Navbar />
			<ListingWrapper>
				<LeftInfoSection>
					<ListingBrand>{listingInfo.designerName}</ListingBrand>
					<ListingItemName>{listingInfo.itemName}</ListingItemName>
					<ListingColor>color : {listingInfo.color}</ListingColor>
					<ListingDescription>{listingInfo.description}</ListingDescription>
					<ListingSize>{listingInfo.sizeName}</ListingSize>
				</LeftInfoSection>
				<ImageSection>
					{listingImage
					.filter(image => image[1] !== null)
					.map(image => <Image key={image[0]} image={image[1]}/>)
					}
				</ImageSection>
				<RightInfoSection>
					<ListingCondition>{listingInfo.conditionName}</ListingCondition>
					<ListingPrice>{listingInfo.price}</ListingPrice>
					<Warning>Shipping fees will be calculated upon checkout.</Warning>
					<AddToCart>PURCHASE</AddToCart>
					<Message onClick={onMessage}>MESSAGE SELLER</Message>
					{isLiked ? <Liked onClick={onLike}/> : <Like onClick={onLike}/>}
				</RightInfoSection>
			</ListingWrapper>
			<MoreFromThisDesigner>
				<MoreFromThisDesignerTitle>MORE FROM THIS DESIGNER</MoreFromThisDesignerTitle>
				{filteredListing.map(listing => <ListingCard key={listing.id} id={listing.id}>{listing}</ListingCard>)}
			</MoreFromThisDesigner>
			{chatroomActive ? <MessageBox>
				<MessageBoxBody>
					{messageData.map((message, index) => 
					<>
						{index > 0 ? 
						(differenceInMinutes(parseISO(message.createdAt), parseISO(messageData[index - 1].createdAt)) > 10 ? 
						<Time>{parseISO(message.createdAt).toString().split(' GMT+0800 (Taipei Standard Time)')[0]}</Time> : null) : <Time>{parseISO(message.createdAt).toString().split(' GMT+0800 (Taipei Standard Time)')[0]}</Time>}
						<Message key={message.id} message={message}/>
					</>
					)}
					<MessageBoxInput onKeyDown={onKeyin} type='text' onChange={onInput} value={inputValue} placeholder='Message...'></MessageBoxInput>
				</MessageBoxBody>
			</MessageBox> : null}
		</>
	)
}
